                      {participant.terms_accepted ? "Yes" : "No"}
                    </td>
                    <td className="px-4 py-3 text-zinc-700">
                      {participant.terms_version ?? "-"}
                    </td>
                    <td className="px-4 py-3 text-zinc-700">{participant.attendance_status}</td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </section>

